    case none
    case start(start: Int64
    )
    case end(end: Int64
    )
    case duration(duration: UInt32
    )
    case startAndEnd(start: Int64, end: Int64
    )
    case startAndDuration(start: Int64, durationMs: UInt32
    )
    case durationAndEnd(durationMs: UInt32, end: Int64
    )





}

